SELECT
t.*,
t1.real_name create_user_name
FROM
member_level t
LEFT OUTER JOIN castle_sys_user t1 ON t.create_user = t1.id
WHERE
t.is_deleted = 2

    AND t.id = #{memberLevelEntity.id}


    AND t.level = #{memberLevelEntity.level}


    AND t.name like concat('%',#{memberLevelEntity.name},'%')


    AND t.up_conditions = #{memberLevelEntity.upConditions}


    AND t.order_total = #{memberLevelEntity.orderTotal}


    AND t.order_count = #{memberLevelEntity.orderCount}


    AND t.goods_id = #{memberLevelEntity.goodsId}


    AND t.discount = #{memberLevelEntity.discount}


    AND t.create_user = #{memberLevelEntity.createUser}


    AND t.create_time = #{memberLevelEntity.createTime}


    AND t.update_user = #{memberLevelEntity.updateUser}


    AND t.update_time = #{memberLevelEntity.updateTime}


    AND t.status = #{memberLevelEntity.status}


    AND t.is_deleted = #{memberLevelEntity.isDeleted}

order by create_time desc

    limit #{map.offset},#{map.rows}

SELECT
count(1)
FROM
member_level t
WHERE
t.is_deleted = 2

    AND t.id = #{memberLevelEntity.id}


    AND t.level = #{memberLevelEntity.level}


    AND t.name like concat('%',#{memberLevelEntity.name},'%')


    AND t.up_conditions = #{memberLevelEntity.upConditions}


    AND t.order_total = #{memberLevelEntity.orderTotal}


    AND t.order_count = #{memberLevelEntity.orderCount}


    AND t.goods_id = #{memberLevelEntity.goodsId}


    AND t.discount = #{memberLevelEntity.discount}


    AND t.create_user = #{memberLevelEntity.createUser}


    AND t.create_time = #{memberLevelEntity.createTime}


    AND t.update_user = #{memberLevelEntity.updateUser}


    AND t.update_time = #{memberLevelEntity.updateTime}


